# scripts/verify_artifact.py
"""Verify artifact immutability before environment promotion."""
import json, subprocess, sys, pathlib, hashlib

def get_running_digest(namespace: str) -> str:
    result = subprocess.run(
        ["kubectl", "get", "deployment", "myapp", "-n", namespace,
         "-o", "jsonpath={.spec.template.spec.containers[0].image}"],
        capture_output=True, text=True, check=True,
    )
    image = result.stdout.strip()
    # Expected format: myregistry/myapp:1.3.2@sha256:abc123
    if "@sha256:" not in image:
        raise ValueError(f"Image not pinned by digest: {image}")
    return image.split("@sha256:")[1]

def get_expected_digest() -> str:
    return pathlib.Path("build/image_digest.txt").read_text().strip()

def hash_prompts(prompts_dir: str = "prompts/") -> str:
    h = hashlib.sha256()
    for p in sorted(pathlib.Path(prompts_dir).rglob("*")):
        if p.is_file():
            h.update(p.read_bytes())
    return h.hexdigest()[:16]

def verify_envelope(namespace: str) -> dict:
    result = subprocess.run(
        ["kubectl", "exec", "-n", namespace,
         "deployment/myapp", "--", "cat", "/app/version_envelope.json"],
        capture_output=True, text=True,
    )
    if result.returncode != 0:
        raise RuntimeError("Could not read version envelope from running pod")
    return json.loads(result.stdout)

def main(namespace: str, expected_digest: str):
    errors = []

    running_digest = get_running_digest(namespace)
    if running_digest != expected_digest:
        errors.append(f"Digest mismatch: running={running_digest} expected={expected_digest}")
    else:
        print(f"Digest OK: sha256:{running_digest[:16]}...")

    envelope = verify_envelope(namespace)
    print(f"Version envelope: {json.dumps(envelope, indent=2)}")

    if errors:
        for e in errors:
            print(f"FAIL: {e}")
        sys.exit(1)
    print("Artifact immutability verified.")

if __name__ == "__main__":
    import argparse
    p = argparse.ArgumentParser()
    p.add_argument("--namespace", required=True)
    p.add_argument("--expected-digest", required=True)
    args = p.parse_args()
    main(args.namespace, args.expected_digest)

